sys_script.script:
(function executeRule(current, previous) {
      try { 
          if (!current.car_name || !current.car_chassi) {
              return finalize(current, 'Nome do carro e chassi sao obrigatorios');
          }

          var rm = new sn_ws.RESTMessageV2('Chain External Car Service', 'getCarByNameAndChassi');
          rm.setStringParameterNoEscape('name', encodeURIComponent(current.car_name.toString()));
          rm.setStringParameterNoEscape('chassi', encodeURIComponent(current.car_chassi.toString()));

          var resp = rm.execute(); 
          var status = resp.getStatusCode();
          if (status != 200) {
              return finalize(current, 'API externa status=' + status + ' ' + resp.getErrorMessage());
          }

          var body = JSON.parse(resp.getBody());
          if (!body.result || body.result.length === 0) {
              return finalize(current, 'Veiculo nao encontrado: nome="' + current.car_name + '", chassi="' + current.car_chassi + '"');
          }

          var car = body.result[0];
          current.car_brand = car.u_marca || '';
          current.car_model = car.u_modelo || '';
          current.car_color = car.u_cor || '';
          current.car_year_model = parseInt(car.u_ano_modelo, 10) || 0;
          current.car_year_manufacture = parseInt(car.u_ano_fabricacao, 10) || 0;
          current.car_uf = car.u_uf || '';
          current.car_fipe_value = parseFloat(car.u_valor_tabela_fipe) || 0;
          current.car_info_snapshot = car.u_marca + ' ' + car.u_modelo + ' / Cor: ' + car.u_cor + ' / FIPE: R$ ' + car.u_valor_tabela_fipe + ' / UF: ' + car.u_uf;

          if (car.u_proprietario && car.u_proprietario.value) {
              var u = new GlideRecord('sys_user');
              u.addQuery('x_1880990_chain_u_chain_external_sys_id', car.u_proprietario.value);
              u.query();
              if (u.next()) {   
                  current.owner = u.sys_id.toString();
              } else {
                  return finalize(current, 'Owner externo ' + car.u_proprietario.value + ' nao mapeado em sys_user');
              }
          }

          if (current.car_uf) {
              var ufrm = new GlideRecord('x_1880990_chain_uf_region_manager');
              ufrm.addQuery('uf', current.car_uf.toString());
              ufrm.query();
              if (ufrm.next()) {
                  current.state_manager = ufrm.manager.toString();
              } else {
                  return finalize(current, 'Regional manager nao encontrado para UF ' + current.car_uf);
              }
          } 

          finalize(current, null);

      } catch (e) {
          gs.error('[enrich] exception: ' + e.message);
          finalize(current, 'Erro inesperado: ' + e.message);
      }

      function finalize(current, errorMsg) {
          if (errorMsg) {
              current.external_api_error = errorMsg;
              current.state = 10;
          } else {
              current.state = 20;
          }
          current.update();
      }
  })(current, previous);
